import{_ as o,c as a,a3 as t,o as l}from"./chunks/framework.CAwIQbWu.js";const b=JSON.parse('{"title":"记6分题","description":"","frontmatter":{},"headers":[],"relativePath":"SubjectOne/记分题/记6分题.md","filePath":"SubjectOne/记分题/记6分题.md","lastUpdated":1737264998000}'),c={name:"SubjectOne/记分题/记6分题.md"};function r(i,e,d,n,u,s){return l(),a("div",null,e[0]||(e[0]=[t('<h1 id="记6分题" tabindex="-1">记6分题 <a class="header-anchor" href="#记6分题" aria-label="Permalink to &quot;记6分题&quot;">​</a></h1><h2 id="_1-扣留期间驾驶-暂扣开车、无证驾驶" tabindex="-1">1. 扣留期间驾驶（暂扣开车、无证驾驶） <a class="header-anchor" href="#_1-扣留期间驾驶-暂扣开车、无证驾驶" aria-label="Permalink to &quot;1. 扣留期间驾驶（暂扣开车、无证驾驶）&quot;">​</a></h2><ul><li><strong>记6分</strong></li><li>罚款200-2000元</li><li>15日以下拘留</li></ul><blockquote><p>机动车驾驶证被暂扣或者扣留期间驾驶机动车的，一次记6分。</p></blockquote><blockquote><p>机动车驾驶证被暂扣期间驾驶机动车的，处罚款200-2000元，并处15日以下拘留。</p></blockquote><h2 id="_2-运载爆炸物品-未悬挂" tabindex="-1">2. 运载爆炸物品，未悬挂 <a class="header-anchor" href="#_2-运载爆炸物品-未悬挂" aria-label="Permalink to &quot;2. 运载爆炸物品，未悬挂&quot;">​</a></h2><ul><li><strong>记6分</strong></li></ul><blockquote><p>运载爆炸物品，未悬挂警示标志并采取必要安全措施，一次记6分。</p></blockquote><h2 id="_3-超载-0-20" tabindex="-1">3. 超载(0%-20%) <a class="header-anchor" href="#_3-超载-0-20" aria-label="Permalink to &quot;3. 超载(0%-20%)&quot;">​</a></h2><ul><li><strong>记6分</strong></li></ul><blockquote><p>驾驶<code>校车</code>、<code>公路客运汽车</code>、<code>旅游客运汽车</code>载人超过核定人数未达20%的，一次记6分。</p></blockquote><h2 id="_4-超速-0-20" tabindex="-1">4. 超速(0%-20%) <a class="header-anchor" href="#_4-超速-0-20" aria-label="Permalink to &quot;4. 超速(0%-20%)&quot;">​</a></h2><ul><li><strong>记6分</strong></li></ul><blockquote><p>驾驶<code>校车</code>、<code>公路客运汽车</code>、<code>旅游客运汽车</code>在高速公路、城市快速路上行驶超速未达20%的，一次记6分。</p></blockquote><h2 id="_5-逃逸-轻微伤" tabindex="-1">5. 逃逸（轻微伤） <a class="header-anchor" href="#_5-逃逸-轻微伤" aria-label="Permalink to &quot;5. 逃逸（轻微伤）&quot;">​</a></h2><ul><li><strong>记6分</strong></li><li>处15日拘留</li><li>罚款200-2000元</li></ul><blockquote><p>驾驶机动车造成致人轻微伤或者财产损失的交通事故后逃逸，<code>尚不构成犯罪的</code>，一次记6分。</p></blockquote><blockquote><p>凡是肇事逃逸者，吊销驾驶证，且终生不得重新申领。所以这里不是<code>肇事逃逸者</code>。</p></blockquote><blockquote><p>凡是逃逸的（<code>构成犯罪的</code>），终生不得重新申领驾驶证。</p></blockquote><blockquote><p>造成交通事故后逃逸，尚不构成犯罪的，处15日拘留，并处罚款200-2000元。</p></blockquote><h2 id="_6-不按交通信号灯通行-闯红灯" tabindex="-1">6. 不按交通信号灯通行（闯红灯...） <a class="header-anchor" href="#_6-不按交通信号灯通行-闯红灯" aria-label="Permalink to &quot;6. 不按交通信号灯通行（闯红灯...）&quot;">​</a></h2><ul><li><strong>记6分</strong></li></ul>',22)]))}const q=o(c,[["render",r]]);export{b as __pageData,q as default};
